use super::super::super::{DeploymentManifest, SIGNER_SIDECAR_ROOT};
use super::super::quote::sh_literal;

pub(in crate::private_network) fn render_unix_health_script(
    manifest: &DeploymentManifest,
) -> String {
    let mut text = format!(
        "#!/usr/bin/env sh\nset -eu\n\n# Generated by NeoNexus for {} / magic {}.\ncd \"$(dirname \"$0\")\"\ntimeout=\"${{NEONEXUS_HEALTH_TIMEOUT_SECONDS:-60}}\"\ninterval=\"${{NEONEXUS_HEALTH_INTERVAL_SECONDS:-2}}\"\ndeadline=$(( $(date +%s) + timeout ))\nfailures=0\n\nok() {{\n  echo \"OK: $1\"\n}}\n\nwarn() {{\n  echo \"WARN: $1\"\n}}\n\nfail() {{\n  echo \"FAIL: $1\"\n  failures=1\n}}\n\npid_file_alive() {{\n  pid_file=\"$1\"\n  [ -f \"$pid_file\" ] || return 1\n  pid=\"$(cat \"$pid_file\")\"\n  kill -0 \"$pid\" 2>/dev/null\n}}\n\npid_alive() {{\n  name=\"$1\"\n  workdir=\"$2\"\n  pid_file_alive \"$workdir/$name.pid\"\n}}\n\nsigner_pid_alive() {{\n  label=\"$1\"\n  pid_file_alive \"{SIGNER_SIDECAR_ROOT}/$label/$label.pid\"\n}}\n\nport_open() {{\n  port=\"$1\"\n  if command -v nc >/dev/null 2>&1; then\n    nc -z 127.0.0.1 \"$port\" >/dev/null 2>&1\n    return $?\n  fi\n  if command -v lsof >/dev/null 2>&1; then\n    lsof -nP -iTCP:\"$port\" -sTCP:LISTEN >/dev/null 2>&1\n    return $?\n  fi\n  return 2\n}}\n\nhttp_ready() {{\n  endpoint=\"$1\"\n  if ! command -v curl >/dev/null 2>&1; then\n    return 2\n  fi\n  curl -fsS -m 2 -o /dev/null \"$endpoint\" >/dev/null 2>&1\n}}\n\nrpc_ready() {{\n  port=\"$1\"\n  if ! command -v curl >/dev/null 2>&1; then\n    return 2\n  fi\n  curl -fsS -m 2 -H 'Content-Type: application/json' \\\n    --data '{{\"jsonrpc\":\"2.0\",\"method\":\"getblockcount\",\"params\":[],\"id\":1}}' \\\n    \"http://127.0.0.1:$port\" >/dev/null 2>&1\n}}\n\nwait_signer() {{\n  label=\"$1\"\n  endpoint=\"$2\"\n  while [ \"$(date +%s)\" -le \"$deadline\" ]; do\n    if signer_pid_alive \"$label\"; then\n      if [ \"$endpoint\" = \"-\" ]; then\n        ok \"signer $label process is healthy\"\n        return 0\n      fi\n      set +e\n      http_ready \"$endpoint\"\n      endpoint_status=$?\n      set -e\n      if [ \"$endpoint_status\" -eq 0 ]; then\n        ok \"signer $label endpoint is healthy\"\n        return 0\n      fi\n      if [ \"$endpoint_status\" -eq 2 ]; then\n        warn \"curl not found; endpoint probe skipped for signer $label\"\n        ok \"signer $label process is healthy\"\n        return 0\n      fi\n    fi\n    sleep \"$interval\"\n  done\n  fail \"signer $label did not become healthy within ${{timeout}}s\"\n}}\n\nnode_ready() {{\n  name=\"$1\"\n  workdir=\"$2\"\n  rpc_port=\"$3\"\n  p2p_port=\"$4\"\n  ws_port=\"$5\"\n  pid_alive \"$name\" \"$workdir\" || return 1\n  port_open \"$rpc_port\" || return 1\n  port_open \"$p2p_port\" || return 1\n  if [ \"$ws_port\" != \"0\" ]; then\n    port_open \"$ws_port\" || return 1\n  fi\n  set +e\n  rpc_ready \"$rpc_port\"\n  rpc_status=$?\n  set -e\n  if [ \"$rpc_status\" -eq 0 ] || [ \"$rpc_status\" -eq 2 ]; then\n    return 0\n  fi\n  return 1\n}}\n\nwait_node() {{\n  name=\"$1\"\n  workdir=\"$2\"\n  rpc_port=\"$3\"\n  p2p_port=\"$4\"\n  ws_port=\"$5\"\n  while [ \"$(date +%s)\" -le \"$deadline\" ]; do\n    if node_ready \"$name\" \"$workdir\" \"$rpc_port\" \"$p2p_port\" \"$ws_port\"; then\n      ok \"$name is healthy\"\n      if ! command -v curl >/dev/null 2>&1; then\n        warn \"curl not found; RPC JSON probe skipped for $name\"\n      fi\n      return 0\n    fi\n    sleep \"$interval\"\n  done\n  fail \"$name did not become healthy within ${{timeout}}s\"\n}}\n\n",
        manifest.runtime, manifest.network_magic
    );
    append_unix_health_signers(&mut text, manifest);
    for node in &manifest.nodes {
        text.push_str(&format!(
            "wait_node {} {} {} {} {}\n",
            sh_literal(&node.name),
            sh_literal(&node.working_dir),
            node.rpc_port,
            node.p2p_port,
            node.ws_port.unwrap_or(0)
        ));
    }
    text.push_str(
        "\nif [ \"$failures\" -ne 0 ]; then\n  echo \"Health check failed\"\n  exit 1\nfi\n\necho \"Health check passed\"\n",
    );
    text
}

fn append_unix_health_signers(text: &mut String, manifest: &DeploymentManifest) {
    let signers = manifest
        .committee
        .signers
        .iter()
        .filter(|signer| signer.signer_command_plan.is_some())
        .collect::<Vec<_>>();
    if signers.is_empty() {
        return;
    }
    text.push_str("# Committee signer sidecar health\n");
    for signer in signers {
        text.push_str(&format!(
            "wait_signer {} {}\n",
            sh_literal(&signer.label),
            sh_literal(signer.signer_endpoint.as_deref().unwrap_or("-"))
        ));
    }
    text.push('\n');
}
